\begin{lemma}
[Rotation lemma for the triple-overlap transitions]
  \label{lem:gr_rotMid}
  \lean{AlgebraicGeometry.Grassmannian.rotMid}
  \uses{def:gr_cocycle_theta_ij, def:gr_cocycle_theta_jk, def:gr_away_mul_comm_equiv, lem:gr_awayMulCommEquiv_comp_algebraMap, lem:gr_awayMulCommEquiv_comp_awayInclLeft}
  Conjugating the rotated transition \(\Theta_{J,K,I}\) (\cref{def:gr_cocycle_theta_ij})
  by the two order-swaps \(\mathrm{swap}\) (\cref{def:gr_away_mul_comm_equiv}) recovers the
  \(J,K\)-transition \(\Theta_{J,K}\) (\cref{def:gr_cocycle_theta_jk}) in the \(I,J,K\) frame:
  \(\mathrm{swap} \circ \Theta_{J,K,I} \circ \mathrm{swap} = \Theta_{J,K}\).
\end{lemma}
\begin{proof}
  Both sides are away-localisation lifts of \(\tilde\theta_{J,K}\); checking on the chart ring
  \(R^K\) reduces to \cref{lem:gr_awayMulCommEquiv_comp_algebraMap} and
  \cref{lem:gr_awayMulCommEquiv_comp_awayInclLeft}. Proved directly in Lean.
\end{proof}

\begin{lemma}
[Matrix collapse behind the inverse pair]
  \label{lem:gr_transitionInvImageMatrix}
  \lean{AlgebraicGeometry.Grassmannian.transitionInvImageMatrix}
  \uses{def:gr_image_matrix, def:gr_cocycle_theta_ik, def:gr_away_incl_left, def:gr_away_incl_right, def:gr_universal_matrix, def:gr_universalMinorInv, def:gr_universal_minor, lem:gr_awayInclLeft_comp_algebraMap, lem:gr_awayInclRight_comp_algebraMap, lem:gr_isUnit_algebraMap_away_right, lem:gr_minorDet_unit, lem:gr_map_map_eq_of_comp, lem:gr_map_nonsing_inv, lem:gr_mul_submatrix_col, lem:gr_universalMatrix_map_transitionPreMap, lem:gr_imageMatrix_map_eq, lem:gr_universalMatrix_submatrix_self}
  Pushing the image matrix \((X^K_I)^{-1} X^K\) (\cref{def:gr_image_matrix}) of \(\theta_{K,I}\)
  forward along \(\theta_{I,K}\) — realised as \(\Theta_{I,K}\) (\cref{def:gr_cocycle_theta_ik})
  post-composed with the left inclusion (\cref{def:gr_away_incl_left}) — recovers the universal
  matrix \(X^I\) (\cref{def:gr_universal_matrix}) over the triple-overlap ring \(S_I\).
\end{lemma}
\begin{proof}
  Both sides reduce to \(W = X^I\) over \(S_I\) via the \((W_K)^{-1} W\) collapse, using
  \(W_I = 1\) (\cref{lem:gr_universalMatrix_submatrix_self}), naturality of the image matrix
  (\cref{lem:gr_imageMatrix_map_eq}) and of the Cramer inverse (\cref{lem:gr_map_nonsing_inv}),
  and the unit \(\det(W_K)\) (\cref{lem:gr_isUnit_algebraMap_away_right}). Proved directly in Lean.
\end{proof}

\begin{lemma}
[The residual inverse pair \(\theta_{I,K} \circ \theta_{K,I} = \id\)]
  \label{lem:gr_transitionInvPair}
  \lean{AlgebraicGeometry.Grassmannian.transitionInvPair}
  \uses{lem:gr_transitionInvImageMatrix, def:gr_cocycle_theta_ik, def:gr_cocycle_theta_ij, def:gr_away_mul_comm_equiv, def:gr_away_incl_left, def:gr_transition_pre, def:gr_universal_matrix, lem:gr_awayMulCommEquiv_comp_algebraMap}
  Over the triple-overlap ring \(S_I = R^I[1/(P^I_J P^I_K)]\) the inverse pair, phrased through the
  localised transitions and the order-swap, is the identity:
  \(\Theta_{I,J,K} \circ \Theta_{K,I,J} \circ \mathrm{swap}_I = \id\)
  (\cref{def:gr_cocycle_theta_ik}, \cref{def:gr_cocycle_theta_ij},
  \cref{def:gr_away_mul_comm_equiv}).
\end{lemma}
\begin{proof}
  By \(\mathrm{IsLocalization.ringHom\_ext}\) it suffices to check on the chart-ring generators of
  \(X^I\) (\cref{def:gr_universal_matrix}); there the matrix collapse
  \cref{lem:gr_transitionInvImageMatrix} closes each generator. Proved directly in Lean.
\end{proof}

