\begin{definition}
[Base-point lift along \((R \hookrightarrow K)\)]
  \label{def:gr_liftToBaseOfMemRange}
  \lean{AlgebraicGeometry.Grassmannian.liftToBaseOfMemRange}
  A ring homomorphism \(\varphi : A \to K\) into the fraction field \(K\) of a domain \(R\) whose
  image lies in the subring \((R \hookrightarrow K)\) (i.e.\ \(\varphi(x) \in (\mathrm{algebraMap}\,R\,K)\)
  for all \(x\)) corestricts to a ring homomorphism \(\varphi' : A \to R\). This packages the
  factorisation \(g'\) of \cref{lem:gr_existence_factor_through_valuation_ring} in step E5: the
  corestriction along the injective \(\mathrm{rangeRestrict}\) of \(R \hookrightarrow K\) (an iso onto
  its range by \(\mathrm{IsFractionRing.injective}\)).
\end{definition}

\begin{lemma}
[Defining property of the base-point lift]
  \label{lem:gr_algebraMap_comp_liftToBaseOfMemRange}
  \lean{AlgebraicGeometry.Grassmannian.algebraMap_comp_liftToBaseOfMemRange}
  \uses{def:gr_liftToBaseOfMemRange}
  Composing the corestriction \(\varphi'\) (\cref{def:gr_liftToBaseOfMemRange}) back with the
  structure map \(R \hookrightarrow K\) recovers the original map:
  \((\mathrm{algebraMap}\,R\,K) \circ \varphi' = \varphi\).
\end{lemma}
\begin{proof}
  The corestriction inverts the range-restriction iso of \(R \hookrightarrow K\), so re-applying that
  iso (i.e.\ post-composing with \(R \hookrightarrow K\)) returns \(\varphi\). Proved directly in Lean.
\end{proof}

